import { readFile, writeFile } from "node:fs/promises";
import { loadEnvFile } from "node:process";

/* ============================================================
 * Live t00ns cheapest listings + local rarity
 *
 * Requirements:
 * - Node.js 22+
 * - .env containing OPENSEA_API_KEY
 * - t00ns-rank-index.json generated by rarity.mjs
 *
 * Run once:
 *   node live-cheapest.mjs
 *
 * Refresh every 30 seconds:
 *   WATCH_SECONDS=30 node live-cheapest.mjs
 * ============================================================
 */

/* ============================================================
 * Load environment variables
 * ============================================================
 */

try {
  loadEnvFile(".env");
} catch (error) {
  if (error?.code !== "ENOENT") {
    throw error;
  }

  console.error("Could not find .env in the current folder.");
  process.exit(1);
}

/* ============================================================
 * Configuration
 * ============================================================
 */

const OPENSEA_API_KEY =
  process.env.OPENSEA_API_KEY?.trim();

const COLLECTION_SLUG =
  process.env.OPENSEA_COLLECTION_SLUG?.trim() ||
  "just-t00ns-ethereum";

const CONTRACT_ADDRESS =
  "0x902d94ba5bfc0cb408d1a6ca4b8f255d845e50e9";

const CHAIN = "ethereum";

const RANK_INDEX_FILE =
  process.env.RANK_INDEX_FILE?.trim() ||
  "./t00ns-rank-index.json";

const OUTPUT_JSON_FILE =
  "./t00ns-cheapest-live.json";

const OUTPUT_CSV_FILE =
  "./t00ns-cheapest-live.csv";

/*
 * Number of unique NFTs to display.
 */
const RESULT_LIMIT = Math.max(
  1,
  Number(process.env.RESULT_LIMIT ?? 25),
);

/*
 * OpenSea may return multiple listings for the same token.
 * Request more than 10 so the script can deduplicate.
 */
const PAGE_SIZE = Math.min(
  200,
  Math.max(
    RESULT_LIMIT * 5,
    Number(process.env.OPENSEA_PAGE_SIZE ?? 50),
  ),
);

/*
 * Safety limit for pagination.
 */
const MAX_PAGES = Math.max(
  1,
  Number(process.env.MAX_PAGES ?? 5),
);

/*
 * Default is 0, meaning run only once.
 *
 * Example:
 * WATCH_SECONDS=30 node live-cheapest.mjs
 */
const WATCH_SECONDS = Math.max(
  0,
  Number(process.env.WATCH_SECONDS ?? 0),
);

const REQUEST_TIMEOUT_MS = Math.max(
  5_000,
  Number(process.env.REQUEST_TIMEOUT_MS ?? 20_000),
);

if (!OPENSEA_API_KEY) {
  console.error(
    "OPENSEA_API_KEY is missing from your .env file.",
  );

  console.error(
    "Expected format: OPENSEA_API_KEY=your_key_here",
  );

  process.exit(1);
}

/* ============================================================
 * Utility functions
 * ============================================================
 */

function sleep(milliseconds) {
  return new Promise((resolve) => {
    setTimeout(resolve, milliseconds);
  });
}

function formatTimestamp(date = new Date()) {
  return new Intl.DateTimeFormat("en-CA", {
    dateStyle: "medium",
    timeStyle: "medium",
    timeZone: "America/Montreal",
  }).format(date);
}

function csvEscape(value) {
  const text = String(value ?? "");

  if (
    text.includes(",") ||
    text.includes('"') ||
    text.includes("\n")
  ) {
    return `"${text.replaceAll('"', '""')}"`;
  }

  return text;
}

function shortenHash(hash) {
  if (!hash || hash.length < 14) {
    return hash || "—";
  }

  return `${hash.slice(0, 8)}…${hash.slice(-6)}`;
}

/* ============================================================
 * OpenSea response parsing
 * ============================================================
 */

/*
 * OpenSea returns the NFT token in the Seaport offer array.
 *
 * Typical location:
 * listing.protocol_data.parameters.offer[0].identifierOrCriteria
 *
 * Additional fallbacks are included in case the API response
 * exposes the identifier in a newer structured asset field.
 */
function extractTokenId(listing) {
  const candidates = [
    listing?.asset?.identifier,
    listing?.asset?.token_id,
    listing?.asset?.tokenId,

    listing?.nft?.identifier,
    listing?.nft?.token_id,
    listing?.nft?.tokenId,

    listing?.criteria?.identifier,
    listing?.criteria?.token_id,
    listing?.criteria?.tokenId,

    listing?.protocol_data?.parameters
      ?.offer?.[0]?.identifierOrCriteria,

    listing?.protocolData?.parameters
      ?.offer?.[0]?.identifierOrCriteria,

    listing?.protocol_data?.parameters
      ?.offer?.[0]?.identifier_or_criteria,
  ];

  for (const candidate of candidates) {
    if (
      candidate !== undefined &&
      candidate !== null &&
      /^\d+$/.test(String(candidate))
    ) {
      return String(candidate);
    }
  }

  return null;
}

/*
 * Extract the contract address from the listing to ensure
 * we only accept listings belonging to the t00ns contract.
 */
function extractContractAddress(listing) {
  const candidates = [
    listing?.asset?.contract,
    listing?.asset?.contract_address,
    listing?.asset?.contractAddress,

    listing?.nft?.contract,
    listing?.nft?.contract_address,
    listing?.nft?.contractAddress,

    listing?.protocol_data?.parameters
      ?.offer?.[0]?.token,

    listing?.protocolData?.parameters
      ?.offer?.[0]?.token,
  ];

  for (const candidate of candidates) {
    if (
      typeof candidate === "string" &&
      candidate.startsWith("0x")
    ) {
      return candidate.toLowerCase();
    }
  }

  return null;
}

/*
 * OpenSea's structured listing price normally resembles:
 *
 * {
 *   current: {
 *     currency: "ETH",
 *     decimals: 18,
 *     value: "50000000000000000"
 *   }
 * }
 *
 * The fallbacks also support older response formats.
 */
function extractPrice(listing) {
  const current =
    listing?.price?.current ??
    listing?.price;

  const rawValue =
    current?.value ??
    current?.amount ??
    listing?.current_price ??
    listing?.currentPrice ??
    listing?.protocol_data?.parameters
      ?.consideration?.[0]?.startAmount ??
    listing?.protocolData?.parameters
      ?.consideration?.[0]?.startAmount;

  const rawDecimals =
    current?.decimals ??
    listing?.price?.decimals ??
    18;

  const decimals = Number(rawDecimals);

  const currency =
    current?.currency ??
    current?.symbol ??
    listing?.price?.currency ??
    listing?.price?.symbol ??
    "ETH";

  if (
    rawValue === undefined ||
    rawValue === null
  ) {
    return {
      rawValue: null,
      decimals,
      currency,
      numeric: Number.POSITIVE_INFINITY,
      formatted: "Unknown",
    };
  }

  const rawString = String(rawValue);

  /*
   * Some API variants may already return a decimal price such
   * as "0.05". Do not divide that value by 10^18 again.
   */
  if (rawString.includes(".")) {
    const numeric = Number(rawString);

    return {
      rawValue: rawString,
      decimals,
      currency,
      numeric,
      formatted: Number.isFinite(numeric)
        ? formatDecimalPrice(numeric)
        : rawString,
    };
  }

  try {
    const formatted = formatUnits(
      BigInt(rawString),
      decimals,
    );

    return {
      rawValue: rawString,
      decimals,
      currency,
      numeric: Number(formatted),
      formatted,
    };
  } catch {
    const numeric = Number(rawString);

    return {
      rawValue: rawString,
      decimals,
      currency,
      numeric,
      formatted: Number.isFinite(numeric)
        ? formatDecimalPrice(numeric)
        : rawString,
    };
  }
}

function formatUnits(value, decimals) {
  if (!Number.isInteger(decimals) || decimals < 0) {
    throw new Error(
      `Invalid currency decimals: ${decimals}`,
    );
  }

  const negative = value < 0n;
  const absoluteValue = negative ? -value : value;

  if (decimals === 0) {
    return `${negative ? "-" : ""}${absoluteValue}`;
  }

  const divisor = 10n ** BigInt(decimals);

  const whole = absoluteValue / divisor;

  const fraction = String(
    absoluteValue % divisor,
  )
    .padStart(decimals, "0")
    .replace(/0+$/, "");

  const result = fraction
    ? `${whole}.${fraction}`
    : String(whole);

  return negative ? `-${result}` : result;
}

function formatDecimalPrice(value) {
  if (!Number.isFinite(value)) {
    return "Unknown";
  }

  if (value >= 1) {
    return value.toFixed(4).replace(/0+$/, "").replace(/\.$/, "");
  }

  if (value >= 0.01) {
    return value.toFixed(5).replace(/0+$/, "").replace(/\.$/, "");
  }

  return value.toFixed(7).replace(/0+$/, "").replace(/\.$/, "");
}

/* ============================================================
 * Rarity helpers
 * ============================================================
 */

async function loadRankIndex() {
  try {
    const contents = await readFile(
      RANK_INDEX_FILE,
      "utf8",
    );

    const parsed = JSON.parse(contents);

    if (
      !parsed ||
      typeof parsed !== "object" ||
      Array.isArray(parsed)
    ) {
      throw new Error(
        "Rank index must contain a JSON object.",
      );
    }

    return parsed;
  } catch (error) {
    if (error?.code === "ENOENT") {
      console.error(
        `Could not find ${RANK_INDEX_FILE}.`,
      );

      console.error(
        "Run rarity.mjs successfully before running this script.",
      );

      process.exit(1);
    }

    console.error(
      `Could not read rarity index: ${error.message}`,
    );

    process.exit(1);
  }
}

function rarityTier(topPercent) {
  if (!Number.isFinite(topPercent)) {
    return "Unknown";
  }

  if (topPercent <= 1) {
    return "Elite";
  }

  if (topPercent <= 5) {
    return "Very Rare";
  }

  if (topPercent <= 10) {
    return "Rare";
  }

  if (topPercent <= 25) {
    return "Uncommon";
  }

  if (topPercent <= 50) {
    return "Above Avg";
  }

  return "Common";
}

/* ============================================================
 * OpenSea API
 * ============================================================
 */

async function openSeaRequest(url) {
  const controller = new AbortController();

  const timeout = setTimeout(() => {
    controller.abort();
  }, REQUEST_TIMEOUT_MS);

  try {
    const response = await fetch(url, {
      signal: controller.signal,
      headers: {
        accept: "application/json",
        "x-api-key": OPENSEA_API_KEY,
        "user-agent": "t00ns-live-rarity/1.0",
      },
    });

    const bodyText = await response.text();

    let data;

    try {
      data = bodyText
        ? JSON.parse(bodyText)
        : {};
    } catch {
      throw new Error(
        `OpenSea returned invalid JSON: ${bodyText.slice(0, 300)}`,
      );
    }

    if (!response.ok) {
      const retryAfter =
        response.headers.get("retry-after");

      const message =
        data?.detail ??
        data?.error ??
        data?.message ??
        bodyText ??
        response.statusText;

      const rateLimitDetails =
        response.status === 429 && retryAfter
          ? ` Retry after ${retryAfter} seconds.`
          : "";

      throw new Error(
        `OpenSea HTTP ${response.status}: ${message}.${rateLimitDetails}`,
      );
    }

    return {
      data,
      rateLimit: {
        limit:
          response.headers.get(
            "x-ratelimit-limit",
          ),
        remaining:
          response.headers.get(
            "x-ratelimit-remaining",
          ),
        reset:
          response.headers.get(
            "x-ratelimit-reset",
          ),
      },
    };
  } catch (error) {
    if (error?.name === "AbortError") {
      throw new Error(
        `OpenSea request timed out after ${REQUEST_TIMEOUT_MS} ms.`,
      );
    }

    throw error;
  } finally {
    clearTimeout(timeout);
  }
}

async function fetchCheapestUniqueListings() {
  const uniqueListings = new Map();

  let next = null;
  let page = 0;
  let lastRateLimit = null;

  while (
    uniqueListings.size < RESULT_LIMIT &&
    page < MAX_PAGES
  ) {
    page += 1;

    const url = new URL(
      `https://api.opensea.io/api/v2/listings/collection/${encodeURIComponent(
        COLLECTION_SLUG,
      )}/best`,
    );

    url.searchParams.set(
      "limit",
      String(PAGE_SIZE),
    );

    url.searchParams.set(
      "include_private_listings",
      "false",
    );

    if (next) {
      url.searchParams.set(
        "next",
        next,
      );
    }

    const response = await openSeaRequest(
      url.toString(),
    );

    lastRateLimit = response.rateLimit;

    const listings = Array.isArray(
      response.data?.listings,
    )
      ? response.data.listings
      : [];

    if (listings.length === 0) {
      break;
    }

    for (const listing of listings) {
      if (
        listing?.status &&
        listing.status !== "ACTIVE"
      ) {
        continue;
      }

      const tokenId =
        extractTokenId(listing);

      if (!tokenId) {
        continue;
      }

      const listingContract =
        extractContractAddress(listing);

      if (
        listingContract &&
        listingContract !==
          CONTRACT_ADDRESS.toLowerCase()
      ) {
        continue;
      }

      const price =
        extractPrice(listing);

      if (
        !Number.isFinite(price.numeric)
      ) {
        continue;
      }

      const existing =
        uniqueListings.get(tokenId);

      /*
       * Keep only the cheapest active listing for each token.
       */
      if (
        !existing ||
        price.numeric <
          existing.price.numeric
      ) {
        uniqueListings.set(tokenId, {
          tokenId,
          listing,
          price,
        });
      }
    }

    next =
      response.data?.next ??
      response.data?.next_cursor ??
      null;

    if (!next) {
      break;
    }
  }

  const sorted = [
    ...uniqueListings.values(),
  ].sort((left, right) => {
    return (
      left.price.numeric -
        right.price.numeric ||
      Number(left.tokenId) -
        Number(right.tokenId)
    );
  });

  return {
    listings: sorted.slice(
      0,
      RESULT_LIMIT,
    ),
    pagesFetched: page,
    rateLimit: lastRateLimit,
  };
}

/* ============================================================
 * Combine listings with rarity
 * ============================================================
 */

function combineListingWithRarity(
  listingRecord,
  rankIndex,
) {
  const tokenId =
    listingRecord.tokenId;

  const rarity =
    rankIndex[tokenId] ?? null;

  const topPercent =
    rarity?.topPercent !== undefined
      ? Number(rarity.topPercent)
      : null;

  return {
    tokenId,
    name:
      rarity?.name ??
      `just t00ns #${tokenId}`,

    price: listingRecord.price.numeric,
    formattedPrice:
      listingRecord.price.formatted,

    currency:
      listingRecord.price.currency,

    rawPrice:
      listingRecord.price.rawValue,

    currencyDecimals:
      listingRecord.price.decimals,

    rarityRank:
      rarity?.rank ?? null,

    rarityOutOf:
      rarity?.outOf ?? null,

    topPercent,

    rarityTier:
      rarityTier(topPercent),

    rarityScore:
      rarity?.informationScore ?? null,

    traitCount:
      rarity?.traitCount ?? null,

    rarestTraits:
      rarity?.rarestTraits ?? [],

    orderHash:
      listingRecord.listing?.order_hash ??
      listingRecord.listing?.orderHash ??
      null,

    orderCreatedAt:
      listingRecord.listing?.order_created_at ??
      listingRecord.listing?.orderCreatedAt ??
      null,

    openSeaUrl:
      `https://opensea.io/item/${CHAIN}/${CONTRACT_ADDRESS}/${tokenId}`,
  };
}

/* ============================================================
 * Output
 * ============================================================
 */

function createConsoleRows(results) {
  return results.map(
    (item, index) => ({
      cheapest: index + 1,
      id: `#${item.tokenId}`,
      price:
        `${item.formattedPrice} ${item.currency}`,
      rarity:
        item.rarityRank !== null
          ? `#${item.rarityRank}`
          : "N/A",
      outOf:
        item.rarityOutOf ?? "N/A",
      top:
        item.topPercent !== null
          ? `${item.topPercent.toFixed(2)}%`
          : "N/A",
      tier:
        item.rarityTier,
    }),
  );
}

function createCsv(results) {
  const header = [
    "cheapest_position",
    "token_id",
    "price",
    "currency",
    "rarity_rank",
    "rarity_out_of",
    "top_percent",
    "rarity_tier",
    "rarity_score",
    "trait_count",
    "order_hash",
    "opensea_url",
  ].join(",");

  const rows = results.map(
    (item, index) => {
      return [
        index + 1,
        item.tokenId,
        item.formattedPrice,
        csvEscape(item.currency),
        item.rarityRank ?? "",
        item.rarityOutOf ?? "",
        item.topPercent !== null
          ? item.topPercent.toFixed(6)
          : "",
        csvEscape(item.rarityTier),
        item.rarityScore !== null
          ? Number(
              item.rarityScore,
            ).toFixed(12)
          : "",
        item.traitCount ?? "",
        csvEscape(
          item.orderHash ?? "",
        ),
        csvEscape(item.openSeaUrl),
      ].join(",");
    },
  );

  return `${header}\n${rows.join("\n")}\n`;
}

function printBestRarityDeal(results) {
  const ranked = results.filter(
    (item) =>
      Number.isFinite(
        Number(item.rarityRank),
      ),
  );

  if (ranked.length === 0) {
    return;
  }

  const rarest = [...ranked].sort(
    (left, right) =>
      left.rarityRank -
      right.rarityRank,
  )[0];

  console.log("");
  console.log(
    "Rarest NFT among the cheapest listings:",
  );

  console.log(
    `  t00ns #${rarest.tokenId}`,
  );

  console.log(
    `  Price: ${rarest.formattedPrice} ${rarest.currency}`,
  );

  console.log(
    `  Rarity: #${rarest.rarityRank} / ${rarest.rarityOutOf}`,
  );

  console.log(
    `  Top ${rarest.topPercent.toFixed(2)}% — ${rarest.rarityTier}`,
  );

  console.log(
    `  ${rarest.openSeaUrl}`,
  );
}

async function saveResults(
  results,
  metadata,
) {
  const jsonOutput = {
    collectionSlug:
      COLLECTION_SLUG,
    contractAddress:
      CONTRACT_ADDRESS,
    chain: CHAIN,
    retrievedAt:
      new Date().toISOString(),
    pagesFetched:
      metadata.pagesFetched,
    resultCount:
      results.length,
    rateLimit:
      metadata.rateLimit,
    listings:
      results,
  };

  await Promise.all([
    writeFile(
      OUTPUT_JSON_FILE,
      JSON.stringify(
        jsonOutput,
        null,
        2,
      ),
      "utf8",
    ),

    writeFile(
      OUTPUT_CSV_FILE,
      createCsv(results),
      "utf8",
    ),
  ]);
}

/* ============================================================
 * Main refresh cycle
 * ============================================================
 */

const rankIndex =
  await loadRankIndex();

async function refresh() {
  console.clear();

  console.log(
    "t00ns live cheapest listings + rarity",
  );

  console.log(
    `Updated: ${formatTimestamp()}`,
  );

  console.log(
    `Collection: ${COLLECTION_SLUG}`,
  );

  console.log(
    `Searching for ${RESULT_LIMIT} cheapest unique NFTs...`,
  );

  console.log("");

  const liveResponse =
    await fetchCheapestUniqueListings();

  const results =
    liveResponse.listings.map(
      (listing) =>
        combineListingWithRarity(
          listing,
          rankIndex,
        ),
    );

  if (results.length === 0) {
    console.log(
      "No active listings were returned.",
    );

    return;
  }

  console.table(
    createConsoleRows(results),
  );

  printBestRarityDeal(results);

  if (
    liveResponse.rateLimit?.remaining !==
    null
  ) {
    console.log("");
    console.log(
      `OpenSea requests remaining: ${
        liveResponse.rateLimit
          ?.remaining ?? "unknown"
      }`,
    );
  }

  await saveResults(
    results,
    liveResponse,
  );

  console.log("");
  console.log(
    `Saved ${OUTPUT_JSON_FILE}`,
  );

  console.log(
    `Saved ${OUTPUT_CSV_FILE}`,
  );

  if (WATCH_SECONDS > 0) {
    console.log("");
    console.log(
      `Next refresh in ${WATCH_SECONDS} seconds...`,
    );
  }
}

/* ============================================================
 * Start
 * ============================================================
 */

try {
  await refresh();

  if (WATCH_SECONDS > 0) {
    while (true) {
      await sleep(
        WATCH_SECONDS * 1000,
      );

      try {
        await refresh();
      } catch (error) {
        console.error("");
        console.error(
          `Refresh failed: ${error.message}`,
        );

        console.error(
          `Retrying in ${WATCH_SECONDS} seconds...`,
        );
      }
    }
  }
} catch (error) {
  console.error("");
  console.error(
    `Fatal error: ${error.message}`,
  );

  process.exit(1);
}